// =============================================================================
// FORM VALIDATION SCHEMA (ZOD)
// =============================================================================

export const ldapConfigSchema = z.object({
    serverUrl: z.string()
        .min(1, "Server URL is required")
        .regex(/^ldaps?:\/\/.+/, "Server URL must start with ldap:// or ldaps://")
        .refine((val) => {
            // Basic URL validation for LDAP
            try {
                const url = new URL(val);
                return url.port !== "" || val.includes("://");
            } catch {
                return val.includes("://");
            }
        }, "Please enter a valid LDAP server URL"),
    
    bindDn: z.string()
        .min(1, "Bind DN is required")
        .regex(/^CN=|DC=|OU=/i, "Bind DN should follow LDAP format (e.g., CN=user,DC=domain,DC=com)"),
    
    bindPassword: z.string()
        .min(1, "Bind password is required")
        .min(8, "Password must be at least 8 characters long"),
    
    userSearchBase: z.string()
        .min(1, "User search base is required")
        .regex(/^OU=|DC=/i, "Search base should follow LDAP format (e.g., OU=Users,DC=domain,DC=com)"),
    
    userSearchFilter: z.string()
        .min(1, "User search filter is required")
        .refine((val) => val.includes("{username}"), {
            message: "Filter must contain {username} placeholder",
        }),
    
    useTls: z.boolean().default(true),
    
    verifyTlsCertificate: z.boolean().default(true),
    
    enabled: z.boolean().default(false),
}).refine((data) => {
    // If TLS is not used, certificate verification should be disabled
    if (!data.useTls && data.verifyTlsCertificate) {
        return false;
    }
    return true;
}, {
    message: "TLS certificate verification cannot be enabled when TLS is disabled",
    path: ["verifyTlsCertificate"],
});

export type LdapConfigFormValues = z.infer<typeof ldapConfigSchema>;

// =============================================================================
// API FETCHERS & HOOKS (SWR)
// =============================================================================

const fetcher = (url: string) =>
    fetch(url)
        .then((res) => {
            if (!res.ok) throw new Error(`Failed to fetch: ${res.status}`);
            return res.json();
        })
        .catch((err) => {
            console.error("API fetch error:", err);
            throw err;
        });

/**
 * Hook to fetch and manage LDAP configuration using SWR
 * TODO: Coder - implement actual API endpoint
 */
export function useLdapConfig() {
    const { data, error, isLoading, mutate } = useSWR<LdapConfig>(
        "/api/config/ldap",
        fetcher,
        {
            revalidateOnFocus: false,
            shouldRetryOnError: false,
        }
    );

    return {
        config: data,
        error,
        isLoading,
        mutate,
    };
}

/**
 * Hook to test LDAP connection
 * TODO: Coder - implement actual API endpoint
 */
export async function testLdapConnection(config: LdapConfigFormData): Promise<TestConnectionResult> {
    const response = await fetch("/api/config/ldap/test", {
        method: "POST",
        headers: {
            "Content-Type": "application/json",
        },
        body: JSON.stringify({
            server_url: config.serverUrl,
            bind_dn: config.bindDn,
            bind_password: config.bindPassword,
            user_search_base: config.userSearchBase,
            user_search_filter: config.userSearchFilter,
            use_tls: config.useTls,
            verify_tls_certificate: config.verifyTlsCertificate,
        }),
    });

    if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || "Connection test failed");
    }

    return response.json();
}

/**
 * Hook to save LDAP configuration
 * TODO: Coder - implement actual API endpoint
 */
export async function saveLdapConfig(config: LdapConfigFormData): Promise<void> {
    const response = await fetch("/api/config/ldap", {
        method: "POST",
        headers: {
            "Content-Type": "application/json",
        },
        body: JSON.stringify({
            server_url: config.serverUrl,
            bind_dn: config.bindDn,
            bind_password: config.bindPassword,
            user_search_base: config.userSearchBase,
            user_search_filter: config.userSearchFilter,
            use_tls: config.useTls,
            verify_tls_certificate: config.verifyTlsCertificate,
            enabled: config.enabled,
        }),
    });

    if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || "Failed to save LDAP configuration");
    }
}

