/**
 * Password input with show/hide toggle
 * Accessible password field with visibility control
 */
function PasswordInput({
    value,
    onChange,
    placeholder,
    disabled,
    id,
    "aria-describedby": ariaDescribedBy,
    "aria-invalid": ariaInvalid,
}: {
    value: string;
    onChange: (value: string) => void;
    placeholder?: string;
    disabled?: boolean;
    id?: string;
    "aria-describedby"?: string;
    "aria-invalid"?: boolean;
}) {
    const [showPassword, setShowPassword] = useState(false);

    return (
        <div className="relative">
            <Input
                id={id}
                type={showPassword ? "text" : "password"}
                value={value}
                onChange={(e) => onChange(e.target.value)}
                placeholder={placeholder}
                disabled={disabled}
                className="pr-10"
                aria-describedby={ariaDescribedBy}
                aria-invalid={ariaInvalid}
                aria-label="Bind password"
            />
            <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 rounded-sm"
                aria-label={showPassword ? "Hide password" : "Show password"}
                aria-pressed={showPassword}
                tabIndex={0}
            >
                {showPassword ? (
                    <EyeSlash className="h-4 w-4" aria-hidden="true" />
                ) : (
                    <Eye className="h-4 w-4" aria-hidden="true" />
                )}
            </button>
        </div>
    );
}

/**
 * Connection test result display component
 */
function ConnectionTestAlert({
    status,
    result,
}: {
    status: ConnectionTestStatus;
    result: TestConnectionResult | null;
}) {
    if (status === "idle") return null;

    if (status === "testing") {
        return (
            <Alert className="mt-4" role="status" aria-live="polite">
                <Loader2 className="h-4 w-4 animate-spin" aria-hidden="true" />
                <AlertTitle>Testing Connection</AlertTitle>
                <AlertDescription>
                    Attempting to connect to the LDAP server...
                </AlertDescription>
            </Alert>
        );
    }

    if (status === "success" && result) {
        return (
            <Alert 
                variant="default" 
                className="mt-4 border-green-500 bg-green-50 dark:bg-green-950"
                role="status"
                aria-live="polite"
            >
                <CheckCircle className="h-4 w-4 text-green-600" aria-hidden="true" />
                <AlertTitle className="text-green-800 dark:text-green-200">Connection Successful</AlertTitle>
                <AlertDescription className="text-green-700 dark:text-green-300">
                    {result.message}
                    {result.details && (
                        <ul className="mt-2 text-sm list-disc list-inside">
                            {result.details.bind_success && (
                                <li>Bind authentication successful</li>
                            )}
                            {result.details.search_success && (
                                <li>User search successful</li>
                            )}
                            {result.details.users_found !== undefined && (
                                <li>Found {result.details.users_found} user(s)</li>
                            )}
                        </ul>
                    )}
                </AlertDescription>
            </Alert>
        );
    }

    if (status === "error" && result) {
        return (
            <Alert 
                variant="destructive" 
                className="mt-4"
                role="alert"
                aria-live="assertive"
            >
                <AlertCircle className="h-4 w-4" aria-hidden="true" />
                <AlertTitle>Connection Failed</AlertTitle>
                <AlertDescription>{result.message}</AlertDescription>
            </Alert>
        );
    }

    return null;
}

